[Form]
public class ETGConversionToInventoryTable extends FormRun
{
    Set assetTableList = new Set(Types::Record);

}

/// <summary>
/// Performing lookup method of product variant details field.
/// </summary>
/// <param name = "_ctrl">FormStringControl.</param>
/// <param name = "_itemIdFilter">ItemId.</param>
public void lookupRetailVariantId(FormStringControl _ctrl, ItemId _itemIdFilter)
{
    FormRun formRun = classfactory.formRunClass(new Args(formStr(RetailVariantLookup)));
    formRun.args().parm(_itemIdFilter);
    formRun.args().caller(_ctrl);
    formRun.init();
    formRun.run();
    _ctrl.performFormLookup(formRun);
}

/// <summary>
///calling both methods when single and mutliple fixed asset numbers are selected
/// </summary>
public void init()
{
    super();

    FormName formName = element.args().callerName();

    if(element.args().record() && element.args().dataset() == tableNum(AssetTable))
    {
        if(formName == formStr(AssetTableNotAcquiredListPage))
        {
            FormRun formRunAssetTableAcquired = element.args().caller();
            this.initializeAssetTableList(formRunAssetTableAcquired.dataSource());
        }
        if(formName == formStr(AssetTable))
        {
            this.initializeAssetTableSingle(element.args().record());
        }
    }
}

/// <summary>
/// Initializing the AssetTable when multiple FixedAssetNumbers are selected
/// </summary>
/// <param name = "assetTableDS">FormDataSource assetTableDS</param>
public void initializeAssetTableList(FormDataSource assetTableDS)
{
    AssetTable         assetTable;
    InventJournalTrans inventJournalTarns;

    assetTable = assetTableDS.getFirst(1);
    while (assetTable)
    {
        select firstonly RecId, JournalId from inventJournalTarns where inventJournalTarns.ETGAssetId == assetTable.AssetId;
        if(inventJournalTarns.RecId)
        {
            warning (strFmt("@ETG_New:FixedAssetValidation",
            assetTable.AssetId,
            inventJournalTarns.JournalId));
        }
        else
        {
            assetTableList.add(AssetTable::find(assetTable.AssetId));
        }
        assetTable = assetTableDS.getNext();
    }

}

/// <summary>
/// Intializing the AssetTable single fixed asset number is selected.
/// </summary>
/// <param name = "assetTable">AssetTable.</param>
public void initializeAssetTableSingle(AssetTable assetTable)
{
    InventJournalTrans inventJournalTarns;

    select firstonly RecId, JournalId from inventJournalTarns where inventJournalTarns.ETGAssetId == assetTable.AssetId;
    if(inventJournalTarns.RecId)
    {
        warning (strFmt("@ETG_New:FixedAssetValidation",
            assetTable.AssetId,
            inventJournalTarns.JournalId));
    }
    else
    {
        assetTableList.add(assetTable);
    }
}

/// <summary>
///Assigning the values of Fixedasset, Quantity and Date fields.
/// </summary>
public void run()
{
    super();

    str assetIds;
    Qty totalQty;
    AssetTable assetTable;
    SetEnumerator se = assetTableList.getEnumerator();
    while (se.moveNext())
    {
        assetTable    = se.current();
        if(!assetIds)
        {
            assetIds = assetTable.AssetId;
        }
        else
        {
            assetIds = assetIds + "@ETG_New:Assetid" + assetTable.AssetId;
        }

        totalQty = totalQty + assetTable.Quantity;
    }

    ETGConversionToInventoryTable.FixedAssetNumber = assetIds;
    ETGConversionToInventoryTable.AssetQty         = totalQty;
    ETGConversionToInventoryTable.TransDate        = DateTimeUtil::getSystemDate(DateTimeUtil::getUserPreferredTimeZone());
}

/// <summary>
/// Checking the dimensions are active/enabled/not
/// </summary>
private void checkActiveDimension()
{
    InventTable inventTable;
    EcoResTrackingDimensionGroupRecId inventTrackingDimGroupRecId;
    EcoResStorageDimensionGroupRecId  inventStorageDimGroupRecId;
    EcoResProductDimensionGroupRecId productDimGroupId;

    if(!ETGConversionToInventoryTable.ItemNumber)
    {
        return;
    }

    inventTable                 = InventTable::find(ETGConversionToInventoryTable.ItemNumber);
    inventTrackingDimGroupRecId = inventTable.trackingDimensionGroup();
    inventStorageDimGroupRecId  = inventTable.storageDimensionGroup();
    productDimGroupId           = inventTable.productDimensionGroup();

    //check batch is enabled or not
    ETGConversionToInventoryTable_ds.object(fieldNum(ETGConversionToInventoryTable, InventSiteId)).allowEdit(
        EcoResStorageDimensionGroupFldSetup::findByDimensionGroupFieldId(inventStorageDimGroupRecId,
        fieldNum(InventDim, InventSiteId)).IsActive);

    //check warehouse is enabled or not
    ETGConversionToInventoryTable_ds.object(fieldNum(ETGConversionToInventoryTable, InventLocationId)).allowEdit(
        EcoResStorageDimensionGroupFldSetup::findByDimensionGroupFieldId(inventStorageDimGroupRecId,
        fieldNum(InventDim, InventLocationId)).IsActive);

    //check location is enabled or not
    ETGConversionToInventoryTable_ds.object(fieldNum(ETGConversionToInventoryTable, WMSLocationId)).allowEdit(
        EcoResStorageDimensionGroupFldSetup::findByDimensionGroupFieldId(inventStorageDimGroupRecId,
        fieldNum(InventDim, WMSLocationId)).IsActive);

    //check batch is enabled or not
    ETGConversionToInventoryTable_ds.object(fieldNum(ETGConversionToInventoryTable, InventBatchId)).allowEdit(
        EcoResTrackingDimensionGroupFldSetup::findByDimensionGroupFieldId(inventTrackingDimGroupRecId,
        fieldNum(InventDim, InventBatchId)).IsActive);

    //check grade is enabled or not
    ETGConversionToInventoryTable_ds.object(fieldNum(ETGConversionToInventoryTable, Grade)).allowEdit(
        EcoResProductDimensionGroupFldSetup::findByDimensionGroupFieldId(productDimGroupId,
        fieldNum(InventDim, configId)).IsActive);

    // check size is enabled or not
    ETGConversionToInventoryTable_ds.object(fieldNum(ETGConversionToInventoryTable, Size)).allowEdit(
        EcoResProductDimensionGroupFldSetup::findByDimensionGroupFieldId(productDimGroupId,
        fieldNum(InventDim, InventSizeId)).IsActive);

    // check origin is enabled or not
    ETGConversionToInventoryTable_ds.object(fieldNum(ETGConversionToInventoryTable, Origin)).allowEdit(
        EcoResProductDimensionGroupFldSetup::findByDimensionGroupFieldId(productDimGroupId,
        fieldNum(InventDim, InventColorId)).IsActive);

    // check Brand is enabled or not
    ETGConversionToInventoryTable_ds.object(fieldNum(ETGConversionToInventoryTable, Brand)).allowEdit(
        EcoResProductDimensionGroupFldSetup::findByDimensionGroupFieldId(productDimGroupId,
        fieldNum(InventDim, InventStyleId)).IsActive);



}

/// <summary>
/// Reseting the dimension fields when ItemNumber is modified or changed
/// </summary>
private void resetDimFields()
{
    ETGConversionToInventoryTable.InventSiteId          = "";
    ETGConversionToInventoryTable.InventLocationId      = "";
    ETGConversionToInventoryTable.WMSLocationId         = "";
    ETGConversionToInventoryTable.InventBatchId         = "";
    ETGConversionToInventoryTable.Grade                 = "";
    ETGConversionToInventoryTable.Size                  = "";
    ETGConversionToInventoryTable.Origin                = "";
    ETGConversionToInventoryTable.Brand                 = "";
    ETGConversionToInventoryTable.ItemVariantDetails    = "";
}

/// <summary>
///
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    ETGConversionToInventoryTable::lookupProductDimension(
        _formControl,
        ETGConversionToInventoryTable.ItemNumber,
        fieldNum(RetailProductVariantDimensionsView, InventStyleId));
}

/// <summary>
///
/// </summary>
