/// <summary>
///
/// </summary>
/// <param name = "_formControl"></param>
/// <param name = "_filterStr"></param>
public void lookup(FormControl _formControl, str _filterStr)
{
    Query                   query = new Query();
    QueryBuildRange        queryBuildRange;
    QueryBuildDataSource    queryBuildDataSource  = query.addDataSource(tableNum(InventBatch));
    SysTableLookup          tableLookup = SysTableLookup::newParameters(tablenum(InventBatch), _formControl);
    tableLookup.addLookupfield(fieldnum(InventBatch, InventBatchId));
    queryBuildDataSource.orderMode(OrderMode::GroupBy);
    queryBuildDataSource.addGroupByField(fieldNum(InventBatch, InventBatchId));
    queryBuildRange = queryBuildDataSource.addrange(fieldNum(InventBatch, ItemId));
    queryBuildRange.value(ETGConversionToInventoryTable.ItemNumber);
    tableLookup.parmQuery(query);
    tableLookup.performFormLookup();

}

/// <summary>
///Resetting the dimension fields and checking the active dimensions when ItemNum is modified
/// </summary>
public void modified()
{
    super();
    element.resetDimFields();
    element.checkActiveDimension();
}

/// <summary>
/// Calling the Item Variant related data Lookup method.
/// </summary>
/// <param name = "_formControl">FormControl.</param>
/// <param name = "_filterStr">str.</param>
public void lookup(FormControl _formControl, str _filterStr)
{
    element.lookupRetailVariantId(_formControl,ETGConversionToInventoryTable.ItemNumber);
}

/// <summary>
/// Assigning the Item variants when Item Number field is modified
/// </summary>
public void modified()
{
    InventDim inventdimvariant;

    super();
    inventdimvariant                     = InventDimCombination::findVariantId(ETGConversionToInventoryTable.ItemVariantDetails).inventDim();
    ETGConversionToInventoryTable.Brand  = inventdimvariant.InventStyleId;
    ETGConversionToInventoryTable.Size   = inventdimvariant.InventSizeId;
    ETGConversionToInventoryTable.Origin = inventdimvariant.InventColorId;
    ETGConversionToInventoryTable.Grade  = inventdimvariant.configId;

}

