/// <summary>
///Performing the action of Creating Inventory adjustment Journal when clicked ok.
/// </summary>
public void clicked()
{
    super();

    if(assetTableList.elements() == 0)
    {
        throw Error("@ETG_New:FixedAssetRecordValidation");
    }

    MenuFunction menufunction;
    Args args = new Args();
    args.record(ETGConversionToInventoryTable);
    args.parmObject(assetTableList);
    menufunction = new MenuFunction(menuItemActionStr(ETGTrackingNumInventoryJournalCreate), MenuItemType::Action);
    menufunction.run(args);

    element.close();
}
